// ============================================================
// NORMALIZE SCHEMA — Converts any DB schema to standard format
// ============================================================
const items = $input.all();
const ctx = $('🎯 Prepare Client Context').item.json;
const dbType = ctx.db_type;
const dbConfig = ctx.db_config;

let schema = [];

try {
  if (dbType === 'mysql' || dbType === 'postgres' || dbType === 'mssql') {
    // SQL databases return rows directly from INFORMATION_SCHEMA
    schema = items.map(item => ({
      table_name: (item.json.table_name || item.json.TABLE_NAME || '').toLowerCase(),
      column_name: (item.json.column_name || item.json.COLUMN_NAME || '').toLowerCase(),
      data_type: item.json.data_type || item.json.DATA_TYPE || 'unknown',
      is_nullable: item.json.is_nullable || item.json.IS_NULLABLE || 'YES',
      column_key: item.json.column_key || item.json.COLUMN_KEY || ''
    }));

  } else if (dbType === 'airtable') {
    // Airtable returns { tables: [{ name, fields: [{ name, type }] }] }
    const tables = items[0]?.json?.tables || [];
    tables.forEach(table => {
      (table.fields || []).forEach(field => {
        schema.push({
          table_name: table.name,
          column_name: field.name,
          data_type: field.type,
          is_nullable: 'YES',
          column_key: field.id
        });
      });
    });

  } else if (dbType === 'google-sheets') {
    // Google Sheets returns sheet properties; we also need to read first row for headers
    // db_config.tab = sheet tab name, db_config.headers = known headers array (optional)
    const sheets = items[0]?.json?.sheets || [];
    const targetTab = dbConfig.tab || sheets[0]?.properties?.title || 'Sheet1';
    const headers = dbConfig.headers || ['id', 'name', 'status', 'date', 'amount'];
    headers.forEach(header => {
      schema.push({
        table_name: targetTab,
        column_name: header,
        data_type: 'string',
        is_nullable: 'YES',
        column_key: ''
      });
    });

  } else if (dbType === 'bigquery') {
    // BigQuery returns { rows: [[val1, val2, ...]], schema: { fields: [...] } }
    const bqResult = items[0]?.json;
    const fields = bqResult?.schema?.fields || [];
    const rows = bqResult?.rows || [];
    rows.forEach(row => {
      const vals = row.f || [];
      schema.push({
        table_name: vals[0]?.v || '',
        column_name: vals[1]?.v || '',
        data_type: vals[2]?.v || 'STRING',
        is_nullable: vals[3]?.v === 'YES' ? 'YES' : 'NO',
        column_key: ''
      });
    });

  } else if (dbType === 'supabase') {
    // Supabase PostgREST OpenAPI: definitions object
    const definitions = items[0]?.json?.definitions || {};
    Object.entries(definitions).forEach(([tableName, tableDef]) => {
      const properties = tableDef.properties || {};
      Object.entries(properties).forEach(([colName, colDef]) => {
        schema.push({
          table_name: tableName,
          column_name: colName,
          data_type: colDef.type || colDef.format || 'unknown',
          is_nullable: 'YES',
          column_key: colDef.description?.includes('pkey') ? 'PRI' : ''
        });
      });
    });
  }
} catch (err) {
  schema = [{ table_name: 'unknown', column_name: 'error', data_type: err.message, is_nullable: 'YES', column_key: '' }];
}

// Group by table for readable schema text
const tableMap = {};
schema.forEach(col => {
  const tbl = col.table_name;
  if (!tableMap[tbl]) tableMap[tbl] = [];
  const pk = col.column_key === 'PRI' ? ' [PK]' : '';
  const nullable = col.is_nullable === 'NO' ? ' NOT NULL' : '';
  tableMap[tbl].push(`${col.column_name} (${col.data_type}${pk}${nullable})`);
});

const schemaText = Object.entries(tableMap)
  .map(([table, cols]) => `TABLE ${table}:\n  ${cols.join('\n  ')}`)
  .join('\n\n');

return [{
  json: {
    ...ctx,
    live_schema: schemaText,
    schema_raw: schema,
    schema_tables: Object.keys(tableMap),
    schema_table_count: Object.keys(tableMap).length,
    schema_column_count: schema.length
  }
}];

