// ============================================================
// PARSE AI RESPONSE — Extract structured JSON from Claude
// ============================================================
const response = $input.first().json;
const ctx = $('📝 Build AI Prompt').item.json;

// Extract text from Anthropic API response format
let responseText = '';
if (response.content && Array.isArray(response.content)) {
  responseText = response.content.map(block => block.text || '').join('');
} else if (response.message?.content) {
  responseText = response.message.content;
} else if (typeof response === 'string') {
  responseText = response;
}

if (!responseText) {
  throw new Error('Empty response from Claude API. Check your API key and model name.');
}

// Parse JSON from response (handle markdown code blocks)
let parsed;
try {
  // 1. Try direct JSON parse
  parsed = JSON.parse(responseText.trim());
} catch (e1) {
  try {
    // 2. Extract from ```json ... ``` block
    const jsonBlockMatch = responseText.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
    if (jsonBlockMatch) {
      parsed = JSON.parse(jsonBlockMatch[1]);
    } else {
      // 3. Extract first JSON object
      const objectMatch = responseText.match(/\{[\s\S]*\}/);
      if (objectMatch) {
        parsed = JSON.parse(objectMatch[0]);
      } else {
        throw new Error('No JSON found in Claude response: ' + responseText.substring(0, 200));
      }
    }
  } catch (e2) {
    throw new Error('Failed to parse Claude response as JSON: ' + e2.message);
  }
}

// Validate required fields
if (!parsed.query) {
  throw new Error('Claude response missing required "query" field');
}

return [{
  json: {
    // Carry forward all context
    ...ctx,
    // AI generated fields
    ai_query: parsed.query,
    ai_params: parsed.params || [],
    response_template: parsed.response_template || 'Found {{count}} results for your request.',
    ai_explanation: parsed.explanation || '',
    ai_safe: parsed.safe !== false,
    ai_operation: parsed.operation || 'SELECT',
    // Raw for debugging
    _raw_ai_response: responseText
  }
}];

// ============================================================
// FORMAT RESPONSE — Build human-readable Telegram message
// ============================================================
const resultItems = $input.all();
const ctx = $('🔍 Parse AI Response').item.json;

let responseText = '';
const recordCount = resultItems.length;
const dbType = ctx.db_type;
let template = ctx.response_template || '';

try {
  if (recordCount === 0) {
    responseText = `✅ <b>Request Complete</b>\n\nNo matching records found for: "${ctx.user_query}"\n\n<i>${ctx.ai_explanation || ''}</i>`;

  } else if (dbType === 'airtable') {
    // Airtable returns { records: [{ id, fields: {...} }] }
    const records = resultItems[0]?.json?.records || resultItems;
    const count = Array.isArray(resultItems[0]?.json?.records) ? resultItems[0].json.records.length : recordCount;

    if (template && !template.includes('{{count}}') && count === 1) {
      const fields = records[0]?.json?.fields || records[0]?.json || {};
      let filled = template;
      Object.entries(fields).forEach(([k, v]) => {
        filled = filled.replace(new RegExp(`\\{\\{${k}\\}\\}`, 'gi'), v ?? 'N/A');
      });
      filled = filled.replace(/\{\{\w+\}\}/g, 'N/A');
      responseText = `✅ ${filled}`;
    } else {
      responseText = `✅ <b>Found ${count} record(s)</b>\n\n`;
      const displayRecords = Array.isArray(records[0]?.json?.records) ? records[0].json.records.slice(0, 5) : records.slice(0, 5);
      displayRecords.forEach((rec, i) => {
        const fields = rec.fields || rec.json?.fields || rec.json || {};
        responseText += `<b>${i + 1}.</b> `;
        const firstFew = Object.entries(fields).slice(0, 4);
        responseText += firstFew.map(([k, v]) => `${k}: <code>${v}</code>`).join(' | ');
        responseText += '\n';
      });
      if (count > 5) responseText += `<i>...and ${count - 5} more</i>`;
    }

  } else if (dbType === 'google-sheets') {
    // Google Sheets returns { values: [[row1col1, ...], [row2col1, ...]] }
    const sheetData = resultItems[0]?.json;
    const values = sheetData?.values || [];
    const headers = values[0] || [];
    const dataRows = values.slice(1);

    if (dataRows.length === 0) {
      responseText = `✅ No data found matching your request.`;
    } else if (template && dataRows.length === 1) {
      const rowObj = {};
      headers.forEach((h, i) => { rowObj[h] = dataRows[0][i] || ''; });
      let filled = template;
      Object.entries(rowObj).forEach(([k, v]) => {
        filled = filled.replace(new RegExp(`\\{\\{${k}\\}\\}`, 'gi'), v);
      });
      responseText = `✅ ${filled}`;
    } else {
      responseText = `✅ <b>Found ${dataRows.length} row(s)</b>\n\n`;
      dataRows.slice(0, 5).forEach((row, i) => {
        responseText += `<b>${i + 1}.</b> `;
        const pairs = headers.slice(0, 4).map((h, j) => `${h}: <code>${row[j] || ''}</code>`);
        responseText += pairs.join(' | ') + '\n';
      });
      if (dataRows.length > 5) responseText += `<i>...and ${dataRows.length - 5} more</i>`;
    }

  } else if (dbType === 'bigquery') {
    // BigQuery returns { schema: { fields }, rows: [{ f: [{ v }] }] }
    const bqData = resultItems[0]?.json;
    const fields = bqData?.schema?.fields || [];
    const rows = bqData?.rows || [];

    if (rows.length === 0) {
      responseText = `✅ Query returned no results.`;
    } else if (template && rows.length === 1) {
      const rowObj = {};
      fields.forEach((f, i) => { rowObj[f.name] = rows[0].f?.[i]?.v || ''; });
      let filled = template;
      Object.entries(rowObj).forEach(([k, v]) => {
        filled = filled.replace(new RegExp(`\\{\\{${k}\\}\\}`, 'gi'), v);
      });
      responseText = `✅ ${filled}`;
    } else {
      responseText = `✅ <b>Found ${rows.length} result(s)</b>\n\n`;
      rows.slice(0, 5).forEach((row, i) => {
        responseText += `<b>${i + 1}.</b> `;
        const pairs = fields.slice(0, 4).map((f, j) => `${f.name}: <code>${row.f?.[j]?.v || ''}</code>`);
        responseText += pairs.join(' | ') + '\n';
      });
      if (rows.length > 5) responseText += `<i>...and ${rows.length - 5} more</i>`;
    }

  } else {
    // SQL databases (MySQL, Postgres, MSSQL) + Supabase — return plain row objects
    if (template && recordCount === 1) {
      const row = resultItems[0].json;
      let filled = template;
      Object.entries(row).forEach(([k, v]) => {
        filled = filled.replace(new RegExp(`\\{\\{${k}\\}\\}`, 'gi'), v ?? 'N/A');
      });
      filled = filled.replace(/\{\{\w+\}\}/g, 'N/A');
      responseText = `✅ ${filled}`;
    } else if (recordCount === 1) {
      responseText = `✅ <b>Result</b>\n\n`;
      const row = resultItems[0].json;
      Object.entries(row).slice(0, 8).forEach(([k, v]) => {
        responseText += `• <b>${k.replace(/_/g, ' ').toUpperCase()}</b>: <code>${v ?? 'N/A'}</code>\n`;
      });
    } else {
      responseText = `✅ <b>Found ${recordCount} record(s)</b>\n\n`;
      resultItems.slice(0, 5).forEach((item, i) => {
        const row = item.json;
        responseText += `<b>${i + 1}.</b> `;
        const firstFour = Object.entries(row).slice(0, 4);
        responseText += firstFour.map(([k, v]) => `${k}: <code>${v ?? ''}</code>`).join(' | ');
        responseText += '\n';
      });
      if (recordCount > 5) responseText += `<i>...and ${recordCount - 5} more</i>`;
    }
  }

  // Add operation footer
  if (ctx.ai_operation && !['SELECT', 'API_READ'].includes(ctx.ai_operation)) {
    responseText += `\n\n<i>Operation: ${ctx.ai_operation}</i>`;
  }

} catch (err) {
  responseText = `⚠️ <b>Processing Error</b>\n\nRetrieved data but couldn't format it.\nError: ${err.message}`;
}

return [{
  json: {
    chat_id: ctx.chat_id,
    message_id: ctx.message_id,
    response_text: responseText,
    from_name: ctx.from_name,
    client_id: ctx.client_id,
    record_count: recordCount,
    db_type: dbType
  }
}];
